+    if (!arg.startsWith('--')) {
+      result._.push(arg)
+      index += 1
+      continue
+    }
+    const eqIndex = arg.indexOf('=')
+    if (eqIndex !== -1 && eqIndex > 2) {
+      const key = arg.slice(2, eqIndex)
+      result[key] = arg.slice(eqIndex + 1)
+      index += 1
+      continue
+    }
+    const next = argv[index + 1]
+    if (next && !next.startsWith('-')) {
+      result[arg.slice(2)] = next
+      index += 2
+      continue
+    }
+    result[arg.slice(2)] = true
+    index += 1
   }
   return result
